import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('RendererBackendPolicy', () {
    const policy = RendererBackendPolicy();

    test('prefers GPU on healthy target', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: false,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('uses GPU on healthy android emulator in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('falls back to CPU on android emulator when GPU health fails', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
      expect(decision.reasonToken, 'gpu_health_check_failed');
    });

    test('keeps 3D modules on GPU in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.threeD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });
  });

  group('Render validation', () {
    test('detects non-black histogram and progression', () {
      final frameA = Uint8List.fromList(List<int>.filled(16 * 4, 0));
      final frameB = Uint8List.fromList(List<int>.filled(16 * 4, 0));

      // center pixel (1,1) for a 4x4 image
      const center = (1 * 4 + 1) * 4;
      frameB[center] = 64;
      frameB[center + 1] = 96;
      frameB[center + 2] = 128;

      // add additional non-black + changed pixels
      for (int i = 0; i < frameB.length; i += 8) {
        frameB[i] = 32;
        frameB[i + 1] = 16;
        frameB[i + 2] = 48;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });
  });
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return thresholdsFor(moduleId).shouldUseCpuFallback(zoom);
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return thresholdsFor(moduleId).shouldUseDoubleFloat(zoom);
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
bool _isSameHysteresisStreak({
  required String? previousModuleId,
  required String moduleId,
}) =>
    previousModuleId == moduleId;

class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  String? _trackedModuleId;
  int _aboveThresholdCount = 0;
  bool _cpuActive = false;

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    if (!_isSameHysteresisStreak(
      previousModuleId: _trackedModuleId,
      moduleId: moduleId,
    )) {
      _aboveThresholdCount = 0;
      _cpuActive = false;
      _trackedModuleId = moduleId;
    }

    if (overThreshold) {
      _aboveThresholdCount++;
      if (_aboveThresholdCount >= policy.hysteresisFrames) {
        _cpuActive = true;
      }
    } else {
      // Immediately drop back to GPU on zoom-out — no delay needed.
      _aboveThresholdCount = 0;
      _cpuActive = false;
    }

    return _cpuActive;
  }

  void reset() {
    _trackedModuleId = null;
    _aboveThresholdCount = 0;
    _cpuActive = false;
  }
}

import 'dart:math' as math;
import 'dart:typed_data';

const int _rgbaStride = 4;
const int _blackThreshold = 8;
const int _differenceThreshold = 12;
const double _minimumNonBlackRatio = 0.01;
const double _minimumProgressionRatio = 0.002;
const double _minimumIterationDeltaRatio = 0.01;

class _RenderFrameGeometry {
  final int width;
  final int height;
  final int totalPixels;
  final int centerIndex;

  const _RenderFrameGeometry._({
    required this.width,
    required this.height,
    required this.totalPixels,
    required this.centerIndex,
  });

  factory _RenderFrameGeometry({required int width, required int height}) {
    final totalPixels = width <= 0 || height <= 0 ? 0 : width * height;
    if (totalPixels == 0) {
      return _RenderFrameGeometry._(
        width: width,
        height: height,
        totalPixels: 0,
        centerIndex: -1,
      );
    }

    final cx = (width / 2).floor();
    final cy = (height / 2).floor();
    return _RenderFrameGeometry._(
      width: width,
      height: height,
      totalPixels: totalPixels,
      centerIndex: (cy * width + cx) * _rgbaStride,
    );
  }

  bool canReadCenter(Uint8List frame) =>
      centerIndex >= 0 && centerIndex + 2 < frame.length;

  int readablePixelCount(Uint8List frame) =>
      math.min(totalPixels, frame.length ~/ _rgbaStride);

  bool hasCompleteFrame(Uint8List frame) =>
      totalPixels > 0 && readablePixelCount(frame) == totalPixels;
}

bool _isNonBlack(Uint8List frame, int index) =>
    frame[index] > _blackThreshold ||
    frame[index + 1] > _blackThreshold ||
    frame[index + 2] > _blackThreshold;

bool _isVisiblyDifferent(Uint8List frameA, Uint8List frameB, int index) {
  final dr = (frameB[index] - frameA[index]).abs();
  final dg = (frameB[index + 1] - frameA[index + 1]).abs();
  final db = (frameB[index + 2] - frameA[index + 2]).abs();
  return dr + dg + db > _differenceThreshold;
}

int _countNonBlackPixels(Uint8List frame, int readablePixels) {
  int nonBlack = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isNonBlack(frame, i)) {
      nonBlack++;
    }
  }
  return nonBlack;
}

int _countDifferentPixels({
  required Uint8List frameA,
  required Uint8List frameB,
  required int readablePixels,
}) {
  int different = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isVisiblyDifferent(frameA, frameB, i)) {
      different++;
    }
  }
  return different;
}

class RenderFrameStats {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;

  const RenderFrameStats({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
  });

  String summary(String backend) {
    return '[renderer] render_frame_stats backend=$backend center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} histogram_sane=$histogramSane';
  }
}

RenderFrameStats validateRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final cIndex = geometry.centerIndex;
  final centerR = geometry.canReadCenter(frame) ? frame[cIndex] : 0;
  final centerG = geometry.canReadCenter(frame) ? frame[cIndex + 1] : 0;
  final centerB = geometry.canReadCenter(frame) ? frame[cIndex + 2] : 0;

  final centerNonBlack =
      geometry.canReadCenter(frame) && _isNonBlack(frame, cIndex);

  final readablePixels = geometry.readablePixelCount(frame);
  final nonBlack = _countNonBlackPixels(frame, readablePixels);

  final nonBlackRatio =
      geometry.totalPixels == 0 ? 0.0 : nonBlack / geometry.totalPixels;
  final histogramSane = nonBlackRatio > _minimumNonBlackRatio;

  return RenderFrameStats(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
  );
}

class RenderCheckResult {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;
  final bool frameProgressed;
  final bool iterationDeltaVisible;

  const RenderCheckResult({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
    required this.frameProgressed,
    required this.iterationDeltaVisible,
  });

  bool get pass =>
      centerNonBlack &&
      histogramSane &&
      frameProgressed &&
      iterationDeltaVisible;

  String summary(String backend) {
    return '[renderer] render_check backend=$backend pass=$pass center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} frame_progressed=$frameProgressed iter_delta=$iterationDeltaVisible';
  }
}

RenderCheckResult validateRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final cIndex = geometry.centerIndex;
  final centerR = geometry.canReadCenter(frameB) ? frameB[cIndex] : 0;
  final centerG = geometry.canReadCenter(frameB) ? frameB[cIndex + 1] : 0;
  final centerB = geometry.canReadCenter(frameB) ? frameB[cIndex + 2] : 0;

  final centerNonBlack =
      geometry.canReadCenter(frameB) && _isNonBlack(frameB, cIndex);

  final frameBReadablePixels = geometry.readablePixelCount(frameB);
  final comparablePixels = math.min(
    geometry.readablePixelCount(frameA),
    frameBReadablePixels,
  );
  final nonBlack = _countNonBlackPixels(frameB, frameBReadablePixels);
  final different = _countDifferentPixels(
    frameA: frameA,
    frameB: frameB,
    readablePixels: comparablePixels,
  );
  final hasCompletePair =
      geometry.hasCompleteFrame(frameA) && geometry.hasCompleteFrame(frameB);

  final nonBlackRatio =
      geometry.totalPixels == 0 ? 0.0 : nonBlack / geometry.totalPixels;
  final histogramSane = nonBlackRatio > _minimumNonBlackRatio;
  // Progression is a whole-frame claim; a truncated frame can still prove the
  // current histogram, but cannot prove frame-to-frame movement.
  final progressionRatio = geometry.totalPixels == 0 || !hasCompletePair
      ? 0.0
      : different / geometry.totalPixels;
  final frameProgressed = progressionRatio > _minimumProgressionRatio;
  final iterationDeltaVisible = progressionRatio > _minimumIterationDeltaRatio;

  return RenderCheckResult(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
    frameProgressed: frameProgressed,
    iterationDeltaVisible: iterationDeltaVisible,
  );
}

import 'dart:async' show Timer, unawaited;
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Manages exploration history with back/forward navigation and favorites.
///
/// [HistoryProvider] tracks the user's journey through fractal space,
/// allowing them to:
/// - Navigate back to previously visited locations
/// - Navigate forward after going back
/// - Save favorite spots with custom names
/// - View and jump to any point in history
///
/// History is automatically persisted to local storage.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final history = HistoryProvider(store: historyStore);
///
/// // Record current location
/// history.recordLocation(
///   moduleId: 'mandelbrot',
///   view: controller.view,
///   params: controller.params,
/// );
///
/// // Navigate back
/// if (history.canGoBack) {
///   final entry = history.goBack();
///   // Apply entry to controller
/// }
/// ```
class HistoryProvider extends ChangeNotifier {
  final HistoryStore _store;

  /// All recorded history entries (oldest first).
  List<HistoryEntry> _history = [];

  /// Current position in history (index into _history).
  /// -1 means no history, 0+ is the index.
  int _currentIndex = -1;

  /// User's saved favorite locations.
  List<HistoryEntry> _favorites = [];

  /// Debounce timer to avoid recording too many entries during quick navigation.
  Timer? _debounceTimer;
  static const Duration _debounceDelay = Duration(milliseconds: 500);

  /// Last recorded state to detect meaningful changes.
  HistoryEntry? _lastRecorded;

  /// Creates a new [HistoryProvider].
  HistoryProvider({required HistoryStore store}) : _store = store {
    _loadFromStorage();
  }

  /// Whether navigation to a previous location is possible.
  bool get canGoBack => _currentIndex > 0;

  /// Whether navigation to a later location is possible.
  ///
  /// Only available after going back.
  bool get canGoForward => _currentIndex < _history.length - 1;

  /// The current history entry, if any.
  HistoryEntry? get currentEntry =>
      _currentIndex >= 0 && _currentIndex < _history.length
          ? _history[_currentIndex]
          : null;

  /// All history entries (oldest first).
  List<HistoryEntry> get history => List.unmodifiable(_history);

  /// Number of entries in history.
  int get historyCount => _history.length;

  /// Current position in history (1-indexed for display).
  int get currentPosition => _currentIndex + 1;

  /// All saved favorites.
  List<HistoryEntry> get favorites => List.unmodifiable(_favorites);

  /// Number of saved favorites.
  int get favoritesCount => _favorites.length;

  void _loadFromStorage() {
    _history = _store.loadHistory();
    _favorites = _store.loadFavorites();
    _currentIndex = _history.isEmpty ? -1 : _history.length - 1;
    if (_history.isNotEmpty) {
      _lastRecorded = _history.last;
    }
  }

  /// Records the current location in history.
  ///
  /// If the user has gone back and then makes a change,
  /// forward history is discarded (like a browser).
  ///
  /// Debounces rapid changes to avoid cluttering history
  /// with intermediate positions during smooth navigation.
  void recordLocation({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
  }) {
    final viewSnapshot = snapshotHistoryView(view);
    final paramsSnapshot = snapshotHistoryParams(params);

    _debounceTimer?.cancel();
    _debounceTimer = Timer(_debounceDelay, () {
      _doRecordLocation(moduleId, viewSnapshot, paramsSnapshot);
    });
  }

  void _doRecordLocation(
    String moduleId,
    FractalViewState view,
    Map<String, Object> params,
  ) {
    final entry = HistoryEntry.fromState(
      moduleId: moduleId,
      view: view,
      params: params,
    );

    // Skip if essentially the same location as the last entry
    if (_lastRecorded != null && _lastRecorded!.isSameLocation(entry)) {
      return;
    }

    // If we're not at the end of history, truncate forward history
    if (_currentIndex >= 0 && _currentIndex < _history.length - 1) {
      _history = _history.sublist(0, _currentIndex + 1);
    }

    _history.add(entry);
    _currentIndex = _history.length - 1;
    _lastRecorded = entry;

    unawaited(_store.saveHistory(_history));
    notifyListeners();
  }

  /// Navigates back to the previous location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoBack] is false.
  HistoryEntry? goBack() {
    if (!canGoBack) return null;
    return jumpToIndex(_currentIndex - 1);
  }

  /// Navigates forward to the next location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoForward] is false.
  HistoryEntry? goForward() {
    if (!canGoForward) return null;
    return jumpToIndex(_currentIndex + 1);
  }

  /// Jumps to a specific entry in history by index.
  HistoryEntry? jumpToIndex(int index) {
    if (index < 0 || index >= _history.length) return null;
    _selectHistoryIndex(index);
    notifyListeners();
    return _history[_currentIndex];
  }

  void _selectHistoryIndex(int index) {
    assert(index >= 0 && index < _history.length);
    _currentIndex = index;
    _lastRecorded = _history[index];
  }

  /// Jumps to a specific entry in history by ID.
  HistoryEntry? jumpToEntry(String entryId) {
    final index = _history.indexWhere((e) => e.id == entryId);
    if (index < 0) return null;
    return jumpToIndex(index);
  }

  /// Saves the current location as a favorite.
  ///
  /// Creates a named copy of the current history entry.
  Future<void> saveCurrentAsFavorite(String name) async {
    if (currentEntry == null) return;

    final favorite = currentEntry!.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites.add(favorite);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Saves a specific entry as a favorite.
  Future<void> saveAsFavorite(HistoryEntry entry, String name) async {
    final favorite = entry.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites.add(favorite);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Removes a favorite by ID.
  Future<void> removeFavorite(String favoriteId) async {
    _favorites.removeWhere((f) => f.id == favoriteId);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Renames a favorite.
  Future<void> renameFavorite(String favoriteId, String newName) async {
    final index = _favorites.indexWhere((f) => f.id == favoriteId);
    if (index < 0) return;

    _favorites[index] = _favorites[index].copyWith(name: newName);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Checks if the current location is saved as a favorite.
  bool isCurrentFavorite() {
    if (currentEntry == null) return false;
    return _favorites.any((f) => f.isSameLocation(currentEntry!));
  }

  /// Clears all history.
  Future<void> clearHistory() async {
    _history.clear();
    _currentIndex = -1;
    _lastRecorded = null;
    await _store.clearHistory();
    notifyListeners();
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    _favorites.clear();
    await _store.clearFavorites();
    notifyListeners();
  }

  /// Applies a history entry to a controller-like object.
  ///
  /// Kept intentionally structural so history navigation tests do not depend on
  /// renderer module registration. The controller is expected to expose
  /// `updateParam`, `updateZoom`, `updatePan`, and `updateRotation` methods.
  void applyToController(HistoryEntry entry, Object controller) {
    final target = controller as dynamic;

    // Update parameters
    for (final paramEntry in entry.params.entries) {
      try {
        target.updateParam(paramEntry.key, paramEntry.value);
      } catch (_) {
        // Parameter may not exist in current module
      }
    }

    // Update view state
    target.updateZoom(entry.view.zoom);
    target.updatePan(entry.view.pan);
    target.updateRotation(entry.view.rotation);
  }

  /// Cancels any pending debounced history record.
  void cancelPendingRecord() {
    _debounceTimer?.cancel();
    _debounceTimer = null;
  }

  @override
  void dispose() {
    cancelPendingRecord();
    super.dispose();
  }
}

import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Represents a visited location in fractal exploration history.
///
/// Each entry captures the complete state needed to restore a viewpoint:
/// - The fractal module (type) being viewed
/// - The view state (pan, zoom, rotation)
/// - The fractal parameters at that time
/// - Optional metadata like name (for favorites) and timestamp
///
/// {@category Models}
@immutable
class HistoryEntry {
  /// Unique identifier for this history entry.
  final String id;

  /// The fractal module ID (e.g., 'mandelbrot', 'julia').
  final String moduleId;

  /// The view state (pan, zoom, rotation) at this location.
  final FractalViewState view;

  /// The fractal parameters at this location.
  final Map<String, Object> params;

  /// When this location was visited.
  final DateTime visitedAt;

  /// Optional user-defined name for favorites.
  ///
  /// If non-null, this entry is considered a favorite.
  final String? name;

  /// Whether this entry is marked as a favorite.
  bool get isFavorite => name != null;

  /// Creates a new [HistoryEntry].
  const HistoryEntry({
    required this.id,
    required this.moduleId,
    required this.view,
    required this.params,
    required this.visitedAt,
    this.name,
  });

  /// Creates a history entry from the current fractal state.
  factory HistoryEntry.fromState({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    String? name,
  }) {
    return HistoryEntry(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      moduleId: moduleId,
      view: snapshotHistoryView(view),
      params: snapshotHistoryParams(params),
      visitedAt: DateTime.now(),
      name: name,
    );
  }

  /// Creates a copy with the given fields replaced.
  HistoryEntry copyWith({
    String? id,
    String? moduleId,
    FractalViewState? view,
    Map<String, Object>? params,
    DateTime? visitedAt,
    String? name,
    bool clearName = false,
  }) {
    return HistoryEntry(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      view: view ?? this.view,
      params: params ?? this.params,
      visitedAt: visitedAt ?? this.visitedAt,
      name: clearName ? null : (name ?? this.name),
    );
  }

  /// Serializes this entry to a JSON-compatible map.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'params': params,
      'visitedAt': visitedAt.toIso8601String(),
      'name': name,
    };
  }

  /// Deserializes a history entry from a JSON map.
  static HistoryEntry fromJson(Map<String, Object?> json) {
    final viewJson = json['view'] as Map<String, Object?>? ?? {};
    return HistoryEntry(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      view: FractalViewState(
        pan: Vector2(
          (viewJson['panX'] as num? ?? 0).toDouble(),
          (viewJson['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (viewJson['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (viewJson['rotX'] as num? ?? 0).toDouble(),
          (viewJson['rotY'] as num? ?? 0).toDouble(),
          (viewJson['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      params: (json['params'] as Map?)?.map(
            (key, value) => MapEntry(key as String, value as Object),
          ) ??
          {},
      visitedAt: DateTime.tryParse(json['visitedAt'] as String? ?? '') ??
          DateTime.now(),
      name: json['name'] as String?,
    );
  }

  /// Generates a display label for this entry.
  ///
  /// If named, returns the name. Otherwise, returns a
  /// formatted description of the location.
  String get displayLabel {
    if (name != null) return name!;
    final zoomStr = view.zoom >= 10
        ? '${view.zoom.toStringAsFixed(0)}x'
        : '${view.zoom.toStringAsFixed(1)}x';
    return '$moduleId @ $zoomStr';
  }

  /// Checks if this entry represents the same location as another.
  ///
  /// Two entries are at the same location if they have the same
  /// module, view state, and parameters.
  bool isSameLocation(HistoryEntry other) {
    return isSameHistoryLocation(
      moduleId: moduleId,
      view: view,
      params: params,
      otherModuleId: other.moduleId,
      otherView: other.view,
      otherParams: other.params,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is HistoryEntry && other.id == id;
  }

  @override
  int get hashCode => id.hashCode;
}

import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

/// Creates an immutable-by-convention history snapshot of a mutable view state.
///
/// [FractalViewState] stores mutable vector_math objects, so history must clone
/// those vectors at the record boundary to keep debounced writes replayable.
FractalViewState snapshotHistoryView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

/// Creates a shallow snapshot of the parameter map at the record boundary.
Map<String, Object> snapshotHistoryParams(Map<String, Object> params) {
  return Map<String, Object>.from(params);
}

/// Pure location-equivalence contract for history de-duplication.
///
/// A history location is the restorable fractal state: module, view, and
/// parameters. Metadata such as entry id, favorite name, and timestamp is not
/// part of location identity.
bool isSameHistoryLocation({
  required String moduleId,
  required FractalViewState view,
  required Map<String, Object> params,
  required String otherModuleId,
  required FractalViewState otherView,
  required Map<String, Object> otherParams,
}) {
  if (moduleId != otherModuleId) {
    return false;
  }
  if (view.zoom != otherView.zoom) {
    return false;
  }
  if (view.pan.x != otherView.pan.x || view.pan.y != otherView.pan.y) {
    return false;
  }
  if (view.rotation.x != otherView.rotation.x ||
      view.rotation.y != otherView.rotation.y ||
      view.rotation.z != otherView.rotation.z) {
    return false;
  }
  return haveSameHistoryParams(params, otherParams);
}

/// Compares history parameter snapshots without relying on map iteration order.
bool haveSameHistoryParams(
  Map<String, Object> params,
  Map<String, Object> otherParams,
) {
  if (params.length != otherParams.length) {
    return false;
  }

  for (final entry in params.entries) {
    if (!otherParams.containsKey(entry.key)) {
      return false;
    }
    if (otherParams[entry.key] != entry.value) {
      return false;
    }
  }

  return true;
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:vector_math/vector_math.dart';

HistoryEntry _entry({
  String moduleId = 'mandelbrot',
  double zoom = 1,
  Map<String, Object> params = const <String, Object>{},
}) {
  return HistoryEntry(
    id: 'entry-$moduleId-$zoom-${params.length}',
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: zoom,
      rotation: Vector3.zero(),
    ),
    params: params,
    visitedAt: DateTime.utc(2024),
  );
}

void main() {
  group('HistoryEntry location identity', () {
    test('treats matching module, view, and params as the same location', () {
      final first = _entry(params: {'iterations': 100, 'bailout': 4.0});
      final second = _entry(params: {'bailout': 4.0, 'iterations': 100});

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats parameter changes as a different location', () {
      final first = _entry(params: {'iterations': 100});
      final second = _entry(params: {'iterations': 250});

      expect(first.isSameLocation(second), isFalse);
    });

    test('treats view changes as a different location', () {
      final first = _entry(zoom: 1);
      final second = _entry(zoom: 2);

      expect(first.isSameLocation(second), isFalse);
    });

    test('snapshots mutable view vectors and params when created from state',
        () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';

FractalViewState _view(double zoom) {
  return FractalViewState(
    pan: Vector2.zero(),
    zoom: zoom,
    rotation: Vector3.zero(),
  );
}

Future<void> _recordAndFlush(
  WidgetTester tester,
  HistoryProvider provider, {
  required double zoom,
}) async {
  provider.recordLocation(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  );
  await tester.pump(const Duration(milliseconds: 501));
}

void main() {
  group('HistoryProvider navigation recording', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    testWidgets(
        'replaying the current back entry does not truncate forward history',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);
      await _recordAndFlush(tester, provider, zoom: 3);

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);

      await _recordAndFlush(tester, provider, zoom: 2);

      expect(provider.historyCount, 3);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);
      expect(provider.currentEntry, same(restored));
    });

    testWidgets('records the state passed to the debounced record call',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;
      await tester.pump(const Duration(milliseconds: 501));

      final entry = provider.currentEntry;
      expect(entry, isNotNull);
      expect(entry!.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

HistoryEntry _makeEntry(String id, {String moduleId = 'mandelbrot'}) {
  return HistoryEntry(
    id: id,
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    params: {},
    visitedAt: DateTime.utc(2024, 1, 1),
  );
}

void main() {
  group('HistoryStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await HistoryStore.create();
      expect(store, isNotNull);
    });

    test('loadHistory returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('saveHistory and loadHistory round-trip entries', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('1', moduleId: 'mandelbrot'),
        _makeEntry('2', moduleId: 'julia'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(2));
      expect(loaded[0].id, equals('1'));
      expect(loaded[0].moduleId, equals('mandelbrot'));
      expect(loaded[1].id, equals('2'));
      expect(loaded[1].moduleId, equals('julia'));
    });

    test('history entries maintain insertion order', () async {
      final store = await HistoryStore.create();
      final entries = [
        _makeEntry('first',  moduleId: 'mandelbrot'),
        _makeEntry('second', moduleId: 'julia'),
        _makeEntry('third',  moduleId: 'burning_ship'),
      ];

      await store.saveHistory(entries);
      final loaded = store.loadHistory();

      expect(loaded, hasLength(3));
      expect(loaded[0].id, equals('first'));
      expect(loaded[1].id, equals('second'));
      expect(loaded[2].id, equals('third'));
    });

    test('loadFavorites returns empty list when no data stored', () async {
      final store = await HistoryStore.create();
      expect(store.loadFavorites(), isEmpty);
    });

    test('addFavorite appends entry to favorites', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav1'));
    });

    test('addFavorite does not duplicate existing entry', () async {
      final store = await HistoryStore.create();
      final entry = _makeEntry('fav1');

      await store.addFavorite(entry);
      await store.addFavorite(entry);
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
    });

    test('removeFavorite removes entry by ID', () async {
      final store = await HistoryStore.create();
      await store.addFavorite(_makeEntry('fav1'));
      await store.addFavorite(_makeEntry('fav2'));

      await store.removeFavorite('fav1');
      final favorites = store.loadFavorites();

      expect(favorites, hasLength(1));
      expect(favorites.first.id, equals('fav2'));
    });

    test('clearHistory removes all history', () async {
      final store = await HistoryStore.create();
      await store.saveHistory([_makeEntry('1'), _makeEntry('2')]);

      await store.clearHistory();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory handles corrupted JSON gracefully', () async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': 'not valid json {{{',
      });
      final store = await HistoryStore.create();
      expect(store.loadHistory(), isEmpty);
    });

    test('loadHistory skips corrupted individual entries', () async {
      // Valid JSON array but one entry has missing required fields.
      SharedPreferences.setMockInitialValues({
        'exploration_history':
            '[{"id":"1","moduleId":"mandelbrot","view":{"panX":0,"panY":0,"zoom":1,"rotX":0,"rotY":0,"rotZ":0},"params":{},"visitedAt":"2024-01-01T00:00:00.000Z"},{"bad":"entry"}]',
      });
      final store = await HistoryStore.create();
      final loaded = store.loadHistory();
      // The valid entry should be present; the corrupted one silently skipped.
      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('1'));
    });
  });
}

